var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"이건......","JPN":"これは……","ENG":"This...","TWN":"這是……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"리프노드, 식별코드 다시 확인해.","JPN":"リーフノード、識別コードをもう一度確認して。","ENG":"Leaf Node. Re-confirm the identification code.","TWN":"節點，再次確認識別代碼。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEAFNOD_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>식별코드 재확인.</color>","JPN":"<color=#ffd34c>識別コード、再確認。</color>","ENG":"<color=#ffd34c>Re-confirming identification code.</color>","TWN":"<color=#ffd34c> 識別代碼已確認。</color>"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEAFNOD_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>국방부 제 3차 차원함 전력보충계획 문서번호: 724-BA-Delta.</color>","JPN":"<color=#ffd34c>国防省第3次次元艦の戦力補充計画文書番号: 724-BA-Delta.</color>","ENG":"<color=#ffd34c>Department of Defense, 3rd Dimension Ship Power Supplementation Plan Document No.: 724-BA-Delta.</color>","TWN":"<color=#ffd34c>國防部第3批次補充戰鬥力計畫檔編號：724-BA-Delta.</color>"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEAFNOD_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>뉴 컨스티튜션급 2번함 그레이스호퍼.</color>","JPN":"<color=#ffd34c>ニューコンスティチューション級2番艦グレースホッパー。</color>","ENG":"<color=#ffd34c>The second ship of the New Constitution class, Grace Hopper.</color>","TWN":"<color=#ffd34c> 新憲法級2號艦，葛雷斯霍普。</color>"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEAFNOD_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>이전 검색결과와 일치합니다.</color>","JPN":"<color=#ffd34c>以前の検索結果と一致します。</color>","ENG":"<color=#ffd34c>Matches the previous search result.</color>","TWN":"<color=#ffd34c> 與之前搜索結果一致。</color>"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"말도 안 돼!","JPN":"あり得ない……！","ENG":"No way...","TWN":"不可能！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"뉴 컨스티튜션급은 아직 페이퍼 쉽이라고.","JPN":"ニューコンスティチューション級の艦船は、まだペイパーシップのはず。","ENG":"The New Constitution Class only exists on paper for now.","TWN":"新制鑑船的級別，現在還在紙上作業的階段而已啊。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"네임 쉽도 진수하려면 아무리 빨라도 3년은 더 있어야 하는데 2번함이라니!","JPN":"ネームシップでも進水までは最低3年は待たなきゃならないのに、2番艦だなんて！","ENG":"It should take at least 3 more years to become a name ship, but they're already at the second","TWN":"就算已命名的艦船要試航的話，最快也要3年，但這竟然是2號艦！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEAFNOD_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>식별코드는 정확합니다.</color>","JPN":"<color=#ffd34c>識別コードは間違いありません。</color>","ENG":"<color=#ffd34c>The identification code is accurate.</color>","TWN":"<color=#ffd34c> 識別代碼已確認。</color>"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEAFNOD_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>문제가 있다면 국방부 문서 라이브러리를 재 업데이트해 보시기 바랍니다.</color>","JPN":"<color=#ffd34c>問題がある場合は、国防省の文書ライブラリを再度アップデートしてください。</color>","ENG":"<color=#ffd34c>If there is an issue, please update the document library of the Department of Defense.</color>","TWN":"<color=#ffd34c> 若有問題，請重新更新國防部的資料檔案庫。</color>"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"무슨 문제라도 있나?","JPN":"何か問題か？","ENG":"Is there a problem?","TWN":"有什麼問題嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"......아니. 아무것도 아냐.","JPN":"……いえ、なんでもないわ。","ENG":"No... It's nothing.","TWN":"……沒有，什麼事都沒有。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그보다 잔당들은 다 해결한 거야?","JPN":"それより、残党はすべて片づけたの？","ENG":"Did you guys finish mopping up the rest of them?","TWN":"比起這個，那些殘黨全都解決了嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"보이는 녀석들은 대충...... 조직적인 저항은 끝났다고 봐야겠지.","JPN":"見渡す限りの奴らはだいたいな……組織ぐるみの抵抗は終わったと思う。","ENG":"At least the ones we could find... It's safe to say that any organized resistance is over.","TWN":"我們看得到的傢伙都解決了……或者說有組織的抵抗已經瓦解了。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그건 그렇고 이건 어떡할 거지?","JPN":"それはそうと、これはどうするんだ？","ENG":"Anyway, what should we do with this?","TWN":"話說回來，這該怎麼辦？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"들어서 옮기기엔 좀 큰데.","JPN":"持ち上げて移すには大きすぎると思うんだが。","ENG":"It's too big to carry.","TWN":"要移動的話未免有點太大了。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아무래도 본국에 지원을 요청해야 할 것 같아.","JPN":"本国に支援を要請しないといけないみたい。","ENG":"We'll have to request reinforcements from HQ.","TWN":"看來只能向本國請求支援了。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};